import React from "react";
import { Link } from "react-router-dom";
import ".src/style.css";

function Navbar() {
  return (
    <nav className="navbar">
      <h2>D & S Creations</h2>
      <div>
        <Link to="/">Home</Link>
        <Link to="/designers">Designers</Link>
        <Link to="/complaints">Complaints</Link>
      </div>
    </nav>
  );
}

export default Navbar;
